1	import { defineConfig, loadEnv } from 'vite';
2	import react from '@vitejs/plugin-react';
3	
4	export default defineConfig(({ mode }) => {
5	  const env = loadEnv(mode, '.', '');
6	  const fromApiUrl = env.VITE_API_URL?.replace(/\/api\/v\d+\/?$/, '');
7	  const API_TARGET = env.VITE_DEV_API_TARGET || fromApiUrl || 'http://127.0.0.1:5000';
8	
9	  return {
10	    plugins: [react()],
11	    server: {
12	      port: 5173,
13	      proxy: {
14	        '/api': { target: API_TARGET, changeOrigin: true },
15	        '/socket.io': { target: API_TARGET, changeOrigin: true, ws: true }
16	      }
17	    }
18	  };
19	});
20

1	import axios from 'axios';
2	import { authStore } from '../store/auth.store';
3	
4	/** В dev без .env запросы идут через прокси Vite → тот же порт, что и API (см. vite.config `proxy`). */
5	const baseURL =
6	  import.meta.env.VITE_API_URL ??
7	  (import.meta.env.DEV ? '/api/v1' : 'http://localhost:5000/api/v1');
8	
9	export const axiosInstance = axios.create({
10	  baseURL,
11	  withCredentials: true
12	});
13	
14	axiosInstance.interceptors.response.use(
15	  (response) => response,
16	  (error) => {
17	    if (error?.response?.status === 401) {
18	      authStore.logout();
19	      const path = window.location.pathname;
20	      if (
21	        !path.startsWith('/welcome') &&
22	        !path.startsWith('/login') &&
23	        !path.startsWith('/admin/login') &&
24	        !path.startsWith('/guest')
25	      ) {
26	        const returnUrl = encodeURIComponent(path + window.location.search);
27	        const isAdminPath = path.startsWith('/admin');
28	        window.location.assign(
29	          isAdminPath ? `/admin/login?returnUrl=${returnUrl}` : `/welcome?returnUrl=${returnUrl}`
30	        );
31	      }
32	    }
33	    return Promise.reject(error);
34	  }
35	);
