1	import { axiosInstance } from './axios';
2	import { ApiResponse } from '../types/api.types';
3	import { KtpCatalog, KtpTopicInput } from '../types/ktp.types';
4	
5	export const ktpApi = {
6	  async getCatalog(subjectId: string): Promise<KtpCatalog | null> {
7	    const { data } = await axiosInstance.get<ApiResponse<KtpCatalog | null>>(`/ktp/${subjectId}`);
8	    return data.data;
9	  },
10	
11	  async upsertMeta(subjectId: string, body: { year?: number; version?: number }): Promise<KtpCatalog> {
12	    const { data } = await axiosInstance.post<ApiResponse<KtpCatalog>>(`/ktp/${subjectId}`, body);
13	    return data.data;
14	  },
15	
16	  async addTopic(subjectId: string, body: KtpTopicInput): Promise<KtpCatalog> {
17	    const { data } = await axiosInstance.post<ApiResponse<KtpCatalog>>(`/ktp/${subjectId}/topics`, body);
18	    return data.data;
19	  },
20	
21	  async updateTopic(
22	    subjectId: string,
23	    topicId: string,
24	    body: Partial<KtpTopicInput>
25	  ): Promise<KtpCatalog> {
26	    const { data } = await axiosInstance.patch<ApiResponse<KtpCatalog>>(
27	      `/ktp/${subjectId}/topics/${topicId}`,
28	      body
29	    );
30	    return data.data;
31	  },
32	
33	  async deleteTopic(subjectId: string, topicId: string): Promise<KtpCatalog> {
34	    const { data } = await axiosInstance.delete<ApiResponse<KtpCatalog>>(
35	      `/ktp/${subjectId}/topics/${topicId}`
36	    );
37	    return data.data;
38	  },
39	
40	  async reorder(subjectId: string, orderedTopicIds: string[]): Promise<KtpCatalog> {
41	    const { data } = await axiosInstance.post<ApiResponse<KtpCatalog>>(`/ktp/${subjectId}/reorder`, {
42	      orderedTopicIds
43	    });
44	    return data.data;
45	  },
46	
47	  async import(
48	    subjectId: string,
49	    body: { topics: KtpTopicInput[]; year?: number; version?: number; replace?: boolean }
50	  ): Promise<KtpCatalog> {
51	    const { data } = await axiosInstance.post<ApiResponse<KtpCatalog>>(`/ktp/${subjectId}/import`, body);
52	    return data.data;
53	  }
54	};
55

