1	import React, { useCallback, useEffect, useState } from 'react';
2	import { Link, useParams } from 'react-router-dom';
3	import { ktpApi } from '../../api/ktp.api';
4	import { subjectApi } from '../../api/subject.api';
5	import { KtpCatalog, KtpTopic, KtpTopicInput } from '../../types/ktp.types';
6	import { Loader } from '../../components/ui/Loader';
7	import { ErrorMessage } from '../../components/ui/ErrorMessage';
8	import { SuccessMessage } from '../../components/ui/SuccessMessage';
9	import { Button } from '../../components/ui/Button';
10	import { getApiErrorMessage } from '../../utils/error';
11	
12	/* ───── inline-edit pieces (в стиле SubjectDetailPage) ───── */
13	
14	const EditableText: React.FC<{
15	  text: string;
16	  placeholder?: string;
17	  multiline?: boolean;
18	  onSave: (v: string) => Promise<void>;
19	  className?: string;
20	  emptyLabel?: string;
21	}> = ({ text, placeholder, multiline = false, onSave, className = '', emptyLabel }) => {
22	  const [editing, setEditing] = useState(false);
23	  const [value, setValue] = useState(text);
24	  const [saving, setSaving] = useState(false);
25	
26	  useEffect(() => setValue(text), [text]);
27	
28	  const save = async () => {
29	    if (value.trim() === text.trim()) {
30	      setEditing(false);
31	      return;
32	    }
33	    setSaving(true);
34	    try {
35	      await onSave(value.trim());
36	      setEditing(false);
37	    } finally {
38	      setSaving(false);
39	    }
40	  };
41	
42	  if (editing) {
43	    return (
44	      <span className="inline-flex w-full items-start gap-1.5">
45	        {multiline ? (
46	          <textarea
47	            autoFocus
48	            value={value}
49	            onChange={(e) => setValue(e.target.value)}
50	            rows={3}
51	            className="w-full rounded border border-blue-300 px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-blue-400"
52	          />
53	        ) : (
54	          <input
55	            autoFocus
56	            value={value}
57	            onChange={(e) => setValue(e.target.value)}
58	            placeholder={placeholder}
59	            onKeyDown={(e) => {
60	              if (e.key === 'Enter') void save();
61	              if (e.key === 'Escape') setEditing(false);
62	            }}
63	            className="w-full rounded border border-blue-300 px-2 py-0.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-400"
64	          />
65	        )}
66	        <button onClick={() => void save()} disabled={saving} className="text-xs text-blue-600 hover:underline">
67	          {saving ? '…' : 'OK'}
68	        </button>
69	        <button onClick={() => setEditing(false)} className="text-xs text-slate-400 hover:underline">
70	          Отмена
71	        </button>
72	      </span>
73	    );
74	  }
75	
76	  return (
77	    <span
78	      className={`group/edit cursor-pointer ${className} ${!text && emptyLabel ? 'text-slate-400 italic' : ''}`}
79	      onClick={() => {
80	        setValue(text);
81	        setEditing(true);
82	      }}
83	      title="Нажмите для редактирования"
84	    >
85	      {text || emptyLabel || ''}
86	      <span className="ml-1.5 text-xs text-slate-300 opacity-0 transition group-hover/edit:opacity-100">✏️</span>
87	    </span>
88	  );
89	};
90	
91	const ConfirmDeleteBtn: React.FC<{ label?: string; onConfirm: () => Promise<void> }> = ({
92	  label = 'Удалить',
93	  onConfirm
94	}) => {
95	  const [confirming, setConfirming] = useState(false);
96	  const [deleting, setDeleting] = useState(false);
97	
98	  if (confirming) {
99	    return (
100	      <span className="inline-flex items-center gap-1 text-xs">
101	        <span className="text-red-600">Точно?</span>
102	        <button
103	          onClick={async () => {
104	            setDeleting(true);
105	            await onConfirm();
106	          }}
107	          disabled={deleting}
108	          className="font-medium text-red-600 hover:underline"
109	        >
110	          {deleting ? '…' : 'Да'}
111	        </button>
112	        <button onClick={() => setConfirming(false)} className="text-slate-400 hover:underline">
113	          Нет
114	        </button>
115	      </span>
116	    );
117	  }
118	
119	  return (
120	    <button onClick={() => setConfirming(true)} className="text-xs text-red-400 hover:text-red-600">
121	      {label}
122	    </button>
123	  );
124	};
