126	const AddInline: React.FC<{ placeholder: string; onAdd: (v: string) => Promise<void> }> = ({
127	  placeholder,
128	  onAdd
129	}) => {
130	  const [open, setOpen] = useState(false);
131	  const [value, setValue] = useState('');
132	  const [saving, setSaving] = useState(false);
133	
134	  if (!open) {
135	    return (
136	      <button
137	        onClick={() => setOpen(true)}
138	        className="rounded-lg border border-dashed border-slate-300 px-3 py-1.5 text-xs text-slate-500 transition hover:border-blue-300 hover:text-blue-600"
139	      >
140	        + Добавить тему КТП
141	      </button>
142	    );
143	  }
144	
145	  const submit = async () => {
146	    if (!value.trim()) return;
147	    setSaving(true);
148	    try {
149	      await onAdd(value.trim());
150	      setValue('');
151	      setOpen(false);
152	    } finally {
153	      setSaving(false);
154	    }
155	  };
156	
157	  return (
158	    <div className="flex items-center gap-2">
159	      <input
160	        autoFocus
161	        value={value}
162	        onChange={(e) => setValue(e.target.value)}
163	        onKeyDown={(e) => {
164	          if (e.key === 'Enter') void submit();
165	          if (e.key === 'Escape') setOpen(false);
166	        }}
167	        placeholder={placeholder}
168	        className="w-72 rounded border border-slate-300 px-2 py-1 text-sm focus:border-blue-400 focus:outline-none"
169	      />
170	      <button onClick={() => void submit()} disabled={saving} className="text-xs font-medium text-blue-600 hover:underline">
171	        {saving ? '…' : 'OK'}
172	      </button>
173	      <button onClick={() => setOpen(false)} className="text-xs text-slate-400 hover:underline">
174	        Отмена
175	      </button>
176	    </div>
177	  );
178	};
179	
180	/* ───── main page ───── */
181	
182	export const KtpCatalogPage: React.FC = () => {
183	  const { subjectId } = useParams<{ subjectId: string }>();
184	  const [subjectTitle, setSubjectTitle] = useState('');
185	  const [catalog, setCatalog] = useState<KtpCatalog | null>(null);
186	  const [loading, setLoading] = useState(true);
187	  const [error, setError] = useState<string | null>(null);
188	  const [msg, setMsg] = useState<string | null>(null);
189	
190	  const [yearInput, setYearInput] = useState('');
191	  const [versionInput, setVersionInput] = useState('');
192	
193	  const [importText, setImportText] = useState('');
194	  const [importReplace, setImportReplace] = useState(true);
195	  const [importing, setImporting] = useState(false);
196	
197	  const flash = (m: string) => {
198	    setMsg(m);
199	    setTimeout(() => setMsg(null), 3000);
200	  };
201	
202	  const applyCatalog = (c: KtpCatalog) => {
203	    setCatalog(c);
204	    setYearInput(c.year != null ? String(c.year) : '');
205	    setVersionInput(String(c.version));
206	  };
207	
208	  const reload = useCallback(async () => {
209	    if (!subjectId) return;
210	    setError(null);
211	    try {
212	      const [subject, cat] = await Promise.all([
213	        subjectApi.getSubjectById(subjectId),
214	        ktpApi.getCatalog(subjectId)
215	      ]);
216	      setSubjectTitle(subject.title);
217	      if (cat) applyCatalog(cat);
218	      else {
219	        setCatalog(null);
220	        setYearInput('');
221	        setVersionInput('1');
222	      }
223	    } catch (err) {
224	      setError(getApiErrorMessage(err));
225	    }
226	  }, [subjectId]);
227	
228	  useEffect(() => {
229	    setLoading(true);
230	    reload().finally(() => setLoading(false));
231	  }, [reload]);
232	
233	  if (!subjectId) return <ErrorMessage message="subjectId не указан" />;
234	  if (loading) return <Loader />;
235	  if (error) return <ErrorMessage message={error} />;
236	
237	  const sid = subjectId;
238	  const topics: KtpTopic[] = catalog ? [...catalog.topics].sort((a, b) => a.order - b.order) : [];
239	
240	  const guard = async (fn: () => Promise<KtpCatalog>, okMsg: string) => {
241	    try {
242	      const updated = await fn();
243	      applyCatalog(updated);
244	      flash(okMsg);
245	    } catch (err) {
246	      setError(getApiErrorMessage(err));
247	    }
248	  };
249	
250	  const saveMeta = async () => {
251	    const year = yearInput.trim() ? Number(yearInput.trim()) : undefined;
252	    const version = versionInput.trim() ? Number(versionInput.trim()) : undefined;
253	    await guard(() => ktpApi.upsertMeta(sid, { year, version }), 'Параметры КТП сохранены');
254	  };
255	
256	  const move = async (topicId: string, dir: -1 | 1) => {
257	    const idx = topics.findIndex((t) => t._id === topicId);
258	    const swap = idx + dir;
259	    if (idx < 0 || swap < 0 || swap >= topics.length) return;
260	    const reordered = [...topics];
261	    [reordered[idx], reordered[swap]] = [reordered[swap], reordered[idx]];
262	    await guard(() => ktpApi.reorder(sid, reordered.map((t) => t._id)), 'Порядок обновлён');
263	  };
264	
265	  const doImport = async () => {
266	    if (!importText.trim()) return;
267	    let parsed: unknown;
268	    try {
269	      parsed = JSON.parse(importText);
270	    } catch {
271	      setError('Невалидный JSON');
272	      return;
273	    }
274	    const raw = Array.isArray(parsed)
275	      ? parsed
276	      : (parsed as { topics?: unknown })?.topics;
277	    if (!Array.isArray(raw)) {
278	      setError('Ожидается массив тем или объект { "topics": [...] }');
279	      return;
280	    }
281	    const list = raw as KtpTopicInput[];
282	    setImporting(true);
283	    try {
284	      const updated = await ktpApi.import(sid, { topics: list, replace: importReplace });
285	      applyCatalog(updated);
286	      setImportText('');
287	      flash(`Импортировано тем: ${updated.topics.length}`);
288	    } catch (err) {
289	      setError(getApiErrorMessage(err));
290	    } finally {
291	      setImporting(false);
292	    }
293	  };
294	
295	  return (
296	    <div className="space-y-6">
297	      {/* header */}
298	      <div>
299	        <Link to={`/admin/subjects/${sid}`} className="text-sm text-slate-500 hover:text-slate-800">
300	          ← К предмету
301	        </Link>
302	        <h1 className="mt-2 text-xl font-bold text-slate-900">
