1	import React, { createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';
2	import { useSyncExternalStore } from 'react';
3	import { authApi } from '../api/auth.api';
4	import { testApi } from '../api/test.api';
5	import {
6	  LoginRequest,
7	  VerifyPhoneRequest,
8	  User
9	} from '../types/auth.types';
10	import { getGuestTestSubmission, clearGuestTestSubmission } from '../utils/session';
11	
12	interface AuthStoreState {
13	  user: User | null;
14	}
15	
16	let authState: AuthStoreState = { user: null };
17	const listeners = new Set<() => void>();
18	
19	export const authStore = {
20	  getState: (): AuthStoreState => authState,
21	  setUser: (user: User | null): void => {
22	    authState = { user };
23	    listeners.forEach((listener) => listener());
24	  },
25	  subscribe: (listener: () => void): (() => void) => {
26	    listeners.add(listener);
27	    return () => listeners.delete(listener);
28	  },
29	  logout: (): void => {
30	    authState = { user: null };
31	    listeners.forEach((listener) => listener());
32	  }
33	};
34	
35	interface RequestOtpResult {
36	  channel?: string;
37	  botLink?: string;
38	}
39	
40	interface AuthContextValue {
41	  user: User | null;
42	  isAuthenticated: boolean;
43	  isLoading: boolean;
44	  login: (payload: LoginRequest) => Promise<User>;
45	  loginAdmin: (payload: LoginRequest) => Promise<User>;
46	  requestOtp: (phone: string) => Promise<RequestOtpResult>;
47	  verifyPhone: (payload: VerifyPhoneRequest) => Promise<User>;
48	  logout: () => void;
49	  refresh: () => Promise<void>;
50	}
51	
52	const AuthContext = createContext<AuthContextValue | undefined>(undefined);
53	
54	async function claimPendingGuestTest(): Promise<void> {
55	  const submission = getGuestTestSubmission();
56	  if (!submission) return;
57	  try {
58	    await testApi.claimGuestTest(submission);
59	  } catch {
60	    // ignore — test may already be claimed or expired
61	  } finally {
62	    clearGuestTestSubmission();
63	  }
64	}
65	
66	export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
67	  const storeState = useSyncExternalStore(authStore.subscribe, authStore.getState, authStore.getState);
68	  const [isLoading, setIsLoading] = useState(true);
69	
70	  const refresh = useCallback(async () => {
71	    setIsLoading(true);
72	    try {
73	      const user = await authApi.getMe();
74	      authStore.setUser(user);
75	    } catch {
76	      authStore.setUser(null);
77	    } finally {
78	      setIsLoading(false);
79	    }
80	  }, []);
81	
82	  useEffect(() => {
83	    void refresh();
84	  }, [refresh]);
85	
86	  const login = useCallback(async (payload: LoginRequest) => {
87	    const user = await authApi.login(payload);
88	    authStore.setUser(user);
89	    void claimPendingGuestTest();
90	    return user;
91	  }, []);
92	
93	  const loginAdmin = useCallback(async (payload: LoginRequest) => {
94	    const user = await authApi.loginAdmin(payload);
95	    authStore.setUser(user);
96	    return user;
97	  }, []);
98	
99	  const requestOtp = useCallback(async (phone: string) => {
100	    return authApi.requestOtp(phone);
101	  }, []);
102	
103	  const verifyPhone = useCallback(async (payload: VerifyPhoneRequest) => {
104	    const user = await authApi.verifyPhone(payload);
105	    authStore.setUser(user);
106	    void claimPendingGuestTest();
107	    return user;
108	  }, []);
109	
110	  const logout = useCallback(() => {
111	    authStore.logout();
112	  }, []);
113	
114	  const value = useMemo<AuthContextValue>(
115	    () => ({
116	      user: storeState.user,
117	      isAuthenticated: Boolean(storeState.user),
118	      isLoading,
119	      login,
120	      loginAdmin,
121	      requestOtp,
122	      verifyPhone,
123	      logout,
124	      refresh
125	    }),
126	    [storeState.user, isLoading, login, loginAdmin, requestOtp, verifyPhone, logout, refresh]
127	  );
128	
129	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
130	};
131	
132	export const useAuth = (): AuthContextValue => {
133	  const context = useContext(AuthContext);
134	  if (!context) {
135	    throw new Error('useAuth must be used within AuthProvider');
136	  }
137	  return context;
138	};
