18	function useInlineEdit(initial: string, onSave: (v: string) => Promise<void>) {
19	  const [editing, setEditing] = useState(false);
20	  const [value, setValue] = useState(initial);
21	  const [saving, setSaving] = useState(false);
22	
23	  useEffect(() => {
24	    setValue(initial);
25	  }, [initial]);
26	
27	  const start = () => {
28	    setValue(initial);
29	    setEditing(true);
30	  };
31	
32	  const cancel = () => setEditing(false);
33	
34	  const save = async () => {
35	    if (!value.trim() || value.trim() === initial) {
36	      setEditing(false);
37	      return;
38	    }
39	    setSaving(true);
40	    try {
41	      await onSave(value.trim());
42	      setEditing(false);
43	    } finally {
44	      setSaving(false);
45	    }
46	  };
47	
48	  return { editing, value, setValue, saving, start, cancel, save };
49	}
