27	class KnowledgeComponentService {
28	  private async assertSubject(subjectId: string): Promise<void> {
29	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
30	    const subject = await Subject.findById(subjectId).select('_id').lean();
31	    if (!subject) throw AppError.notFound('Subject not found');
32	  }
33	
34	  /** Найти документ КТП и тему по id; тема должна существовать. */
35	  private async loadCatalogTopic(subjectId: string, ktpTopicId: string) {
36	    if (!mongoose.isValidObjectId(ktpTopicId)) throw AppError.badRequest('Invalid КТП topicId');
37	    const doc = await KtpCatalog.findOne({ subjectId });
38	    if (!doc) throw AppError.notFound('КТП catalog not found');
39	    const topic = doc.topics.find((t) => String(t._id) === ktpTopicId);
40	    if (!topic) throw AppError.notFound('КТП topic not found');
41	    return { doc, topic };
42	  }
43	
44	  /** Источники узла (книга·тема + текст) для грунтинга AI-предложения KC. */
45	  private async resolveNodeSources(
46	    subjectId: string,
47	    ktpTopicId: string
48	  ): Promise<{ nodeTitle: string; nodeDescription?: string; sources: Array<{ label: string; text: string }> }> {
49	    const subject = await Subject.findById(subjectId).lean();
50	    const ktp = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
51	    if (!subject || !ktp) return { nodeTitle: '', sources: [] };
52	    const nodes = buildKtpCanonicalNodes(subject, ktp);
53	    const node = nodes.find(
54	      (n) => (n.metadata as Record<string, unknown> | undefined)?.ktpTopicId === ktpTopicId
55	    );
56	    if (!node) return { nodeTitle: '', sources: [] };
57	    const lessons = ((node.metadata as Record<string, unknown>)?.lessons as
58	      | Array<{ title?: string; content?: string }>
59	      | undefined) ?? [];
60	    const sources = lessons
61	      .map((l) => ({ label: l.title || node.title, text: (l.content || '').trim() }))
62	      .filter((s) => s.text);
63	    return {
64	      nodeTitle: node.title,
65	      ...(node.description ? { nodeDescription: node.description } : {}),
66	      sources
67	    };
68	  }
69	
70	  /** Список KC темы (отсортирован по order). */
71	  async list(subjectId: string, ktpTopicId: string): Promise<IKnowledgeComponent[]> {
72	    await this.assertSubject(subjectId);
73	    const { topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
74	    return sortKc((topic.knowledgeComponents ?? []) as IKnowledgeComponent[]);
75	  }
76	
77	  /** Подтверждённые KC (для консолидации урока и сборки тестов). [] если нет. */
78	  async getConfirmed(subjectId: string, ktpTopicId: string): Promise<Array<{ id: string; title: string }>> {
79	    const ktp = await KtpCatalog.findOne({ subjectId })
80	      .select('topics._id topics.knowledgeComponents')
81	      .lean<IKtpCatalog>();
82	    const topic = ktp?.topics.find((t) => String(t._id) === ktpTopicId);
83	    if (!topic?.knowledgeComponents?.length) return [];
84	    return sortKc(topic.knowledgeComponents)
85	      .filter((k) => k.status === 'confirmed')
86	      .map((k) => ({ id: String(k._id), title: k.title }));
87	  }
88	
89	  /**
90	   * AI-предложение KC: добавляет НОВЫЕ компоненты со статусом 'proposed'.
91	   * Не трогает уже существующие (по нормализованному названию) и подтверждённые.
92	   */
93	  async propose(subjectId: string, ktpTopicId: string): Promise<IKnowledgeComponent[]> {
94	    await this.assertSubject(subjectId);
95	    const { doc, topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
96	
97	    const { nodeTitle, nodeDescription, sources } = await this.resolveNodeSources(subjectId, ktpTopicId);
98	    const proposed = await roadmapAIService.proposeKnowledgeComponents({
99	      subjectTitle: '',
100	      nodeTitle: nodeTitle || topic.title,
101	      ...(nodeDescription || topic.description ? { nodeDescription: nodeDescription || topic.description } : {}),
102	      sources
103	    });
104	
105	    const topicAny = topic as unknown as {
106	      knowledgeComponents?: IKnowledgeComponent[];
107	    };
108	    if (!Array.isArray(topicAny.knowledgeComponents)) topicAny.knowledgeComponents = [];
109	    const existingTitles = new Set(topicAny.knowledgeComponents.map((k) => normTitle(k.title)));
110	    let nextOrder = topicAny.knowledgeComponents.reduce((m, k) => Math.max(m, k.order + 1), 0);
111	
112	    for (const p of proposed) {
113	      if (existingTitles.has(normTitle(p.title))) continue;
114	      existingTitles.add(normTitle(p.title));
115	      topicAny.knowledgeComponents.push({
116	        title: p.title,
117	        ...(p.description ? { description: p.description } : {}),
118	        order: nextOrder++,
119	        status: 'proposed'
120	      } as IKnowledgeComponent);
121	    }
122	
123	    doc.markModified('topics');
124	    await doc.save();
125	    return sortKc(topicAny.knowledgeComponents);
126	  }
127	
128	  /** Подтвердить KC (status='confirmed') по списку id. */
129	  async confirm(subjectId: string, ktpTopicId: string, kcIds: string[]): Promise<IKnowledgeComponent[]> {
130	    await this.assertSubject(subjectId);
131	    const { doc, topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
132	    const ids = new Set(kcIds.map(String));
133	    const list = (topic.knowledgeComponents ?? []) as IKnowledgeComponent[];
134	    list.forEach((k) => {
135	      if (ids.has(String(k._id))) k.status = 'confirmed';
136	    });
137	    doc.markModified('topics');
138	    await doc.save();
139	    return sortKc(list);
140	  }
141	
142	  /** Создать (id отсутствует) или обновить KC. Ручные KC по умолчанию confirmed. */
143	  async upsert(
144	    subjectId: string,
145	    ktpTopicId: string,
146	    input: { id?: string; title?: string; description?: string; order?: number; status?: KnowledgeComponentStatus }
147	  ): Promise<IKnowledgeComponent[]> {
148	    await this.assertSubject(subjectId);
149	    const { doc, topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
150	    const topicAny = topic as unknown as { knowledgeComponents?: IKnowledgeComponent[] };
151	    if (!Array.isArray(topicAny.knowledgeComponents)) topicAny.knowledgeComponents = [];
152	    const list = topicAny.knowledgeComponents;
153	
154	    if (input.id) {
155	      const kc = list.find((k) => String(k._id) === input.id);
156	      if (!kc) throw AppError.notFound('Knowledge component not found');
157	      if (typeof input.title === 'string') {
158	        const t = input.title.trim();
159	        if (!t) throw AppError.badRequest('title cannot be empty');
160	        kc.title = t;
161	      }
162	      if (input.description !== undefined) kc.description = input.description.trim() || undefined;
163	      if (typeof input.order === 'number') kc.order = input.order;
164	      if (input.status) kc.status = input.status;
165	    } else {
166	      const title = input.title?.trim();
167	      if (!title) throw AppError.badRequest('title is required');
168	      const order = typeof input.order === 'number' ? input.order : list.reduce((m, k) => Math.max(m, k.order + 1), 0);
169	      list.push({
170	        title,
171	        ...(input.description?.trim() ? { description: input.description.trim() } : {}),
172	        order,
173	        status: input.status ?? 'confirmed'
174	      } as IKnowledgeComponent);
175	    }
176	
177	    doc.markModified('topics');
178	    await doc.save();
179	    return sortKc(list);
180	  }
181	
182	  async remove(subjectId: string, ktpTopicId: string, kcId: string): Promise<IKnowledgeComponent[]> {
183	    await this.assertSubject(subjectId);
184	    const { doc, topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
185	    const topicAny = topic as unknown as { knowledgeComponents?: IKnowledgeComponent[] };
186	    const list = (topicAny.knowledgeComponents ?? []).filter((k) => String(k._id) !== kcId);
187	    topicAny.knowledgeComponents = list;
188	    doc.markModified('topics');
189	    await doc.save();
190	    // NB: чистка ссылок QuestionItem.knowledgeComponentIds на удалённый KC — в Фазе 2.
191	    return sortKc(list);
192	  }
193	
194	  /** Переупорядочить KC: orderedKcIds — полный список id в нужном порядке. */
195	  async reorder(subjectId: string, ktpTopicId: string, orderedKcIds: string[]): Promise<IKnowledgeComponent[]> {
196	    await this.assertSubject(subjectId);
197	    const { doc, topic } = await this.loadCatalogTopic(subjectId, ktpTopicId);
198	    const idx = new Map(orderedKcIds.map((id, i) => [String(id), i]));
199	    const list = (topic.knowledgeComponents ?? []) as IKnowledgeComponent[];
200	    list.forEach((k) => {
201	      const pos = idx.get(String(k._id));
202	      if (typeof pos === 'number') k.order = pos;
203	    });
204	    doc.markModified('topics');
205	    await doc.save();
206	    return sortKc(list);
207	  }
208	}
